; ワイルド・ブルの隠れ家

name = ワイルド・ブルの隠れ家
insideName = Ｂ１
level = 10
bgm = hideout
shadow = dark
sky = black
roof = stone
blank = rock

; 画像パーツ
━ = soil
　 = soil
❖ = soil
／ = door
〆 = key
☗ = upstair
⑵ = bulletin
⑸ = br_vit
⑹ = barrel
⑺ = br_maxhp

; 敵情報
maxGroups = 2
monsters = ハイウェイマン,ブッシュワッカー,バーグラー
traps = 石つぶて,毒針

; 移動ポイント
(A) = map:エミール平原, x:12, y:18, way:e, symbol:exit, ask:Leave the dungeon?

; 宝箱
box[1] = グレートアックス_u,怪盗のレオタード_u,鉄のブーメラン_u,運の秘薬
box[2] = マジカルボートの巻物

